// ==================== FUQMEA.COM - CENTRAL HUB SCRIPT ====================

// Meme list: single source is assets/images/gallery.json (regenerated by
// generate-gallery.js / CI). Homepage rotator uses the first entry as the
// lead slide, then random picks from the rest.

const GALLERY_JSON_URL = 'assets/images/gallery.json';

/** If gallery.json is missing or fails to load; paths must exist in the repo. */
const FALLBACK_GALLERY_PATHS = [
  'assets/images/01 Vivid - Shocked.jpg',
  'assets/images/Cat - Smile.JPG',
  'assets/images/Emoji - Bonk.png'
];

let galleryListLoadPromise = null;

// ====================== PERFORMANCE OPTIMIZATIONS ======================

function preloadCriticalImages(memes) {
  if (!Array.isArray(memes) || memes.length === 0) return;
  const criticalImages = memes.filter(validateImagePath).slice(0, 3);

  criticalImages.forEach(src => {
    const link = document.createElement('link');
    link.rel = 'preload';
    link.as = 'image';
    link.href = src;
    document.head.appendChild(link);
  });
}

// Optimize for mobile performance
function setupMobileOptimizations() {
  // Reduce motion for battery saving on mobile
  if (window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
    document.documentElement.style.setProperty('--animation-duration', '0s');
  }

  // Passive listeners for better scroll performance
  const gallery = document.getElementById('gallery');
  if (gallery) {
    gallery.addEventListener('touchstart', () => {}, { passive: true });
    gallery.addEventListener('touchmove', () => {}, { passive: true });
  }
}

// Debounce function for performance
function debounce(func, wait) {
  let timeout;
  return function executedFunction(...args) {
    const later = () => {
      clearTimeout(timeout);
      func(...args);
    };
    clearTimeout(timeout);
    timeout = setTimeout(later, wait);
  };
}

// Throttle function for performance
function throttle(func, limit) {
  let inThrottle;
  return function() {
    const args = arguments;
    const context = this;
    if (!inThrottle) {
      func.apply(context, args);
      inThrottle = true;
      setTimeout(() => inThrottle = false, limit);
    }
  }
}

function shuffleArray(array) {
  for (let i = array.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [array[i], array[j]] = [array[j], array[i]];
  }
  return array;
}

// Validate image path to prevent directory traversal attacks
function validateImagePath(path) {
  if (typeof path !== 'string') return false;
  // Only allow paths starting with assets/images/
  if (!path.startsWith('assets/images/')) return false;
  // Prevent directory traversal with ..
  if (path.includes('..') || path.includes('//')) return false;
  return true;
}

function getExtensionFromPath(path) {
  const filename = path.split('/').pop() || '';
  const match = filename.match(/\.([a-zA-Z0-9]+)$/);
  return match ? `.${match[1].toLowerCase()}` : '';
}

function getRandomMemeFilename(extension = '', usedNames) {
  let candidate = '';
  do {
    const randomId = Math.floor(1000 + Math.random() * 9000); // 4 digits
    candidate = `meme_${randomId}${extension}`;
  } while (usedNames && usedNames.has(candidate));
  if (usedNames) usedNames.add(candidate);
  return candidate;
}

async function loadGalleryList() {
  if (galleryListLoadPromise) return galleryListLoadPromise;

  galleryListLoadPromise = (async () => {
    try {
      const res = await fetch(GALLERY_JSON_URL);
      if (!res.ok) throw new Error('gallery.json not found');
      const raw = await res.json();
      let list = [];
      if (Array.isArray(raw)) {
        list = raw;
      } else if (raw && typeof raw === 'object' && Array.isArray(raw.images)) {
        list = raw.images;
        if (typeof raw.featured === 'string' && validateImagePath(raw.featured)) {
          list = [raw.featured, ...list.filter((p) => p !== raw.featured)];
        }
      }
      if (list.length > 0) {
        const validatedList = list.filter(validateImagePath);
        if (validatedList.length > 0) {
          return validatedList;
        }
      }
    } catch (err) {
      console.warn('gallery.json load failed, using fallback');
    }
    return FALLBACK_GALLERY_PATHS.filter(validateImagePath);
  })();

  return galleryListLoadPromise;
}

/** Above-fold-ish thumbnails load eagerly; rest stay lazy so mobile bandwidth isn't flooded. */
const GALLERY_FIRST_EAGER = 12;
const GALLERY_FETCH_PRIORITY_HIGH = 4;

function getFileType(src) {
  return /\.gif$/i.test(src) ? 'gif' : 'image';
}

function renderGallery(memes) {
  const container = document.getElementById('gallery');
  if (!container) return;

  // Clear container safely
  container.innerHTML = '';

  // Create elements without using innerHTML to prevent XSS
  memes.forEach((src, index) => {
    const card = document.createElement('div');
    card.className = 'meme-card';
    card.dataset.src = src;
    const displayName = filenameToDisplay(src);
    const cats = extractCategories(src);
    if (cats.length) {
      card.dataset.categories = cats.join('|');
      card.dataset.category = cats[0];
    }
    card.dataset.type = getFileType(src);

    const img = document.createElement('img');
    img.src = src;
    img.alt = displayName;
    if (index < GALLERY_FIRST_EAGER) {
      img.loading = 'eager';
      img.decoding = index === 0 ? 'sync' : 'async';
      if (index < GALLERY_FETCH_PRIORITY_HIGH && 'fetchPriority' in img) {
        img.fetchPriority = 'high';
      }
    } else {
      img.loading = 'lazy';
      img.decoding = 'async';
    }
    img.addEventListener('click', function() { toggleSelect(this); });

    const viewBtn = document.createElement('button');
    viewBtn.type = 'button';
    viewBtn.className = 'meme-view-btn';
    viewBtn.textContent = 'VIEW';
    viewBtn.setAttribute('aria-label', 'Open meme in lightbox');
    viewBtn.addEventListener('click', (event) => {
      event.stopPropagation();
      openLightboxAt(index, memes);
    });
    
    card.appendChild(img);
    card.appendChild(viewBtn);
    container.appendChild(card);
  });
}

// ====================== SEARCH + FILTER ======================

const FILTER_STORAGE_KEY = 'meme-vault-filters';
const filterState = {
  categories: new Set(),
  type: 'all',
};
let filterPanelOpen = false;
let filterPanelListenersBound = false;

/** Active ordering on Meme Vault (shuffled copy of gallery list). */
let currentGalleryOrder = [];

function filenameToDisplay(src) {
  return src.split('/').pop().replace(/\.[^.]+$/, '').replace(/[-_]/g, ' ').trim();
}

/**
 * Tag rules live in `tools/extract-categories.js` (loaded before hub.js on each page).
 * Fallback mirrors that logic if the script is missing (should not happen on shipped pages).
 */
function normalizeCategoryLabel(label) {
  if (typeof FuqmeaCategories !== 'undefined' && FuqmeaCategories.normalizeCategoryLabel) {
    return FuqmeaCategories.normalizeCategoryLabel(label);
  }
  return label.replace(/^[a-z]{1,3}\s+(?=[A-Za-z0-9])/, '').trim();
}

function extractCategories(src) {
  if (typeof FuqmeaCategories !== 'undefined' && FuqmeaCategories.extractCategories) {
    return FuqmeaCategories.extractCategories(src);
  }
  const name = src.split('/').pop().replace(/\.[^.]+$/, '');
  const parts = name.split(' - ');
  if (parts.length < 2) return [];
  const rawTags = parts.slice(0, -1).map((p) => normalizeCategoryLabel(p.trim())).filter(Boolean);
  return [...new Set(rawTags)];
}

function loadFilterState() {
  try {
    const raw = localStorage.getItem(FILTER_STORAGE_KEY);
    if (!raw) return;
    const o = JSON.parse(raw);
    if (o && Array.isArray(o.categories)) {
      filterState.categories = new Set(o.categories);
    }
    if (o && (o.type === 'all' || o.type === 'gif' || o.type === 'image')) {
      filterState.type = o.type;
    }
  } catch (e) {
    /* ignore */
  }
}

function saveFilterState() {
  try {
    localStorage.setItem(
      FILTER_STORAGE_KEY,
      JSON.stringify({
        categories: Array.from(filterState.categories),
        type: filterState.type,
      })
    );
  } catch (e) {
    /* ignore */
  }
}

function pruneFilterStateToMemes(memes) {
  const validCats = new Set();
  let uncategorised = 0;
  memes.forEach(src => {
    const cats = extractCategories(src);
    if (cats.length) cats.forEach(c => validCats.add(c));
    else uncategorised++;
  });
  const next = new Set();
  filterState.categories.forEach(key => {
    if (key === '__other__') {
      if (uncategorised > 0) next.add(key);
    } else if (validCats.has(key)) {
      next.add(key);
    }
  });
  filterState.categories = next;
}

function syncCategoryChipsFromState() {
  document.querySelectorAll('#filter-chips .filter-chip').forEach(btn => {
    const v = btn.dataset.value;
    if (v === undefined) return;
    const on = filterState.categories.has(v);
    btn.setAttribute('aria-pressed', on ? 'true' : 'false');
  });
}

function syncTypePillsUI() {
  document.querySelectorAll('.filter-type-pill').forEach(btn => {
    const t = btn.dataset.type;
    const on = filterState.type === t;
    btn.classList.toggle('is-active', on);
    btn.setAttribute('aria-pressed', on ? 'true' : 'false');
  });
}

function buildFilterChips(memes) {
  const container = document.getElementById('filter-chips');
  if (!container) return;

  const catCounts = {};
  let uncategorised = 0;
  memes.forEach(src => {
    const cats = extractCategories(src);
    if (cats.length) {
      cats.forEach(cat => {
        catCounts[cat] = (catCounts[cat] || 0) + 1;
      });
    } else uncategorised++;
  });

  const hasCats = Object.keys(catCounts).length > 0;
  const hasOther = uncategorised > 0;
  if (!hasCats && !hasOther) return;

  const addChip = (label, count, value) => {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'filter-chip';
    btn.dataset.value = value;
    btn.textContent = `${label} (${count})`;
    const pressed = filterState.categories.has(value);
    btn.setAttribute('aria-pressed', pressed ? 'true' : 'false');
    btn.addEventListener('click', () => {
      if (filterState.categories.has(value)) {
        filterState.categories.delete(value);
      } else {
        filterState.categories.add(value);
      }
      btn.setAttribute('aria-pressed', filterState.categories.has(value) ? 'true' : 'false');
      saveFilterState();
      applyFilters();
      renderActivePills();
    });
    container.appendChild(btn);
  };

  Object.entries(catCounts)
    .sort((a, b) => b[1] - a[1])
    .forEach(([cat, count]) => addChip(cat, count, cat));

  if (hasOther) {
    addChip('OTHER', uncategorised, '__other__');
  }
}

function initTypePills(memes) {
  const gifCount = memes.filter(s => getFileType(s) === 'gif').length;
  const imageCount = memes.length - gifCount;
  document.querySelectorAll('.filter-type-pill').forEach(btn => {
    const t = btn.dataset.type;
    if (t === 'gif') btn.textContent = `GIFs (${gifCount})`;
    else if (t === 'image') btn.textContent = `Images (${imageCount})`;
    else btn.textContent = 'All';
  });
  syncTypePillsUI();
}

function applyFilters() {
  document.querySelectorAll('.meme-card').forEach(card => {
    const cats = (card.dataset.categories || '')
      .split('|')
      .filter(Boolean);
    const type = card.dataset.type || 'image';

    let catMatches = filterState.categories.size === 0;
    if (!catMatches) {
      if (cats.length && cats.some(c => filterState.categories.has(c))) catMatches = true;
      if (!cats.length && filterState.categories.has('__other__')) catMatches = true;
    }

    const typeMatches = filterState.type === 'all' || filterState.type === type;
    card.classList.toggle('hidden', !(catMatches && typeMatches));
  });
  updateCountDisplay();
  updateFilterSummary();
}

function updateFilterSummary() {
  const summary = document.getElementById('filter-toggle-summary');
  const badge = document.getElementById('filter-toggle-count');
  const applyCount = document.getElementById('filter-apply-count');
  const toggle = document.getElementById('filter-toggle-btn');

  const visible = document.querySelectorAll('.meme-card:not(.hidden)').length;

  const nCat = filterState.categories.size;
  const typeExtra = filterState.type !== 'all';
  const activeCount = nCat + (typeExtra ? 1 : 0);

  const parts = [];
  if (typeExtra) parts.push(filterState.type === 'gif' ? 'GIFs' : 'Images');
  if (nCat > 0) {
    parts.push(nCat === 1 ? '1 category' : `${nCat} categories`);
  }

  if (summary) summary.textContent = parts.length ? ` · ${parts.join(' · ')}` : '';

  if (badge) {
    if (activeCount > 0) {
      badge.hidden = false;
      badge.textContent = String(activeCount);
    } else {
      badge.hidden = true;
    }
  }

  if (toggle) toggle.classList.toggle('filter-active', activeCount > 0);

  if (applyCount) applyCount.textContent = String(visible);
}

function renderActivePills() {
  const wrap = document.getElementById('filter-active-pills');
  if (!wrap) return;
  wrap.textContent = '';
  let any = false;

  if (filterState.type !== 'all') {
    const pill = document.createElement('button');
    pill.type = 'button';
    pill.className = 'filter-active-pill';
    pill.dataset.removeType = '1';
    pill.setAttribute(
      'aria-label',
      `Remove ${filterState.type === 'gif' ? 'GIF' : 'image'} type filter`
    );
    const span = document.createElement('span');
    span.textContent = filterState.type === 'gif' ? 'GIFs' : 'Images';
    const x = document.createElement('span');
    x.className = 'filter-active-pill-x';
    x.setAttribute('aria-hidden', 'true');
    x.textContent = '\u00d7';
    pill.appendChild(span);
    pill.appendChild(x);
    wrap.appendChild(pill);
    any = true;
  }

  filterState.categories.forEach(catKey => {
    const label = catKey === '__other__' ? 'OTHER' : catKey;
    const pill = document.createElement('button');
    pill.type = 'button';
    pill.className = 'filter-active-pill';
    pill.dataset.category = catKey;
    pill.setAttribute('aria-label', `Remove ${label} category filter`);
    const span = document.createElement('span');
    span.textContent = label;
    const x = document.createElement('span');
    x.className = 'filter-active-pill-x';
    x.setAttribute('aria-hidden', 'true');
    x.textContent = '\u00d7';
    pill.appendChild(span);
    pill.appendChild(x);
    wrap.appendChild(pill);
    any = true;
  });

  wrap.hidden = !any;
}

function updateCountDisplay() {
  const total = document.querySelectorAll('.meme-card').length;
  const visible = document.querySelectorAll('.meme-card:not(.hidden)').length;
  const shortText = visible < total ? `${visible} of ${total} memes` : `${total} memes`;

  const el = document.getElementById('selected-count');
  if (el) el.textContent = shortText;

  const fr = document.getElementById('filter-result-count');
  if (fr) {
    fr.textContent =
      visible < total ? `Showing ${visible} of ${total} memes` : `Showing all ${total} memes`;
  }
}

function isMobileFilterViewport() {
  return window.matchMedia && window.matchMedia('(max-width: 767px)').matches;
}

function syncFilterPanelAria() {
  const panel = document.getElementById('filter-panel');
  if (!panel || panel.hasAttribute('hidden')) return;
  panel.setAttribute('aria-modal', isMobileFilterViewport() ? 'true' : 'false');
}

/** Clear JS-set placement so mobile CSS (bottom sheet) is not overridden by desktop inline coords */
function clearDesktopPopoverPosition() {
  const panel = document.getElementById('filter-panel');
  if (!panel) return;
  panel.style.top = '';
  panel.style.left = '';
  panel.style.width = '';
  panel.style.maxHeight = '';
  panel.style.transform = '';
}

/**
 * Desktop: pin filter popunder below FILTER toggle using fixed viewport coords.
 * Must run while #filter-panel is outside .vault-sticky-header so position:fixed is not trapped by backdrop-filter.
 */
function positionDesktopPopover() {
  const panel = document.getElementById('filter-panel');
  const toggle = document.getElementById('filter-toggle-btn');
  if (!panel || !toggle) return;
  if (isMobileFilterViewport()) {
    clearDesktopPopoverPosition();
    return;
  }

  const r = toggle.getBoundingClientRect();
  const margin = 12;
  const width = Math.min(520, window.innerWidth - margin * 2);
  const left = Math.max(
    margin,
    Math.min(window.innerWidth - width - margin, r.left + r.width / 2 - width / 2)
  );
  const top = r.bottom + 6;
  const bottomLimit = window.innerHeight - margin;
  const roomBelow = Math.max(0, bottomLimit - top);
  const maxHeight = Math.min(520, window.innerHeight * 0.7, Math.max(200, roomBelow));

  panel.style.top = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;
  panel.style.width = `${Math.round(width)}px`;
  panel.style.maxHeight = `${Math.round(maxHeight)}px`;
  panel.style.transform = '';
}

function onFilterPanelReposition() {
  if (!filterPanelOpen) return;
  positionDesktopPopover();
}

function openFilterPanel() {
  const panel = document.getElementById('filter-panel');
  const backdrop = document.getElementById('filter-backdrop');
  const toggle = document.getElementById('filter-toggle-btn');
  if (!panel || !toggle) return;

  panel.removeAttribute('hidden');
  if (backdrop) backdrop.removeAttribute('hidden');

  syncFilterPanelAria();

  if (isMobileFilterViewport()) {
    clearDesktopPopoverPosition();
    document.body.style.overflow = 'hidden';
  } else {
    document.body.style.overflow = '';
    requestAnimationFrame(() => {
      positionDesktopPopover();
    });
  }

  toggle.setAttribute('aria-expanded', 'true');
  filterPanelOpen = true;

  requestAnimationFrame(() => {
    const closeBtn = document.getElementById('filter-panel-close');
    if (closeBtn) closeBtn.focus();
  });
}

function closeFilterPanel() {
  if (!filterPanelOpen) return;
  const panel = document.getElementById('filter-panel');
  const backdrop = document.getElementById('filter-backdrop');
  const toggle = document.getElementById('filter-toggle-btn');
  if (!panel) return;

  clearDesktopPopoverPosition();
  panel.setAttribute('hidden', '');
  if (backdrop) backdrop.setAttribute('hidden', '');
  document.body.style.overflow = '';
  if (toggle) {
    toggle.setAttribute('aria-expanded', 'false');
    toggle.focus();
  }
  filterPanelOpen = false;
}

function clearAllFilters() {
  filterState.categories.clear();
  filterState.type = 'all';
  syncCategoryChipsFromState();
  syncTypePillsUI();
  saveFilterState();
  applyFilters();
  renderActivePills();
}

function onFilterPanelTabTrap(e) {
  if (e.key !== 'Tab' || !filterPanelOpen || !isMobileFilterViewport()) return;
  const panel = document.getElementById('filter-panel');
  if (!panel || panel.hasAttribute('hidden')) return;

  const sel =
    'button:not([disabled]), [href], input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])';
  const focusables = Array.from(panel.querySelectorAll(sel)).filter(el => {
    return el.offsetParent !== null || el.getClientRects().length > 0;
  });
  if (focusables.length === 0) return;

  const first = focusables[0];
  const last = focusables[focusables.length - 1];

  if (e.shiftKey) {
    if (document.activeElement === first) {
      e.preventDefault();
      last.focus();
    }
  } else if (document.activeElement === last) {
    e.preventDefault();
    first.focus();
  }
}

function onFilterDocumentClick(e) {
  if (!filterPanelOpen) return;
  const cluster = document.querySelector('.vault-filter-cluster');
  const panel = document.getElementById('filter-panel');
  const backdrop = document.getElementById('filter-backdrop');
  const t = e.target;
  if (cluster && cluster.contains(t)) return;
  if (panel && panel.contains(t)) return;
  if (backdrop && (t === backdrop || backdrop.contains(t))) return;
  closeFilterPanel();
}

function onFilterDocumentKeydown(e) {
  if (e.key !== 'Escape' || !filterPanelOpen) return;
  const lb = document.getElementById('meme-lightbox');
  if (lb && lb.classList.contains('open')) return;
  e.preventDefault();
  closeFilterPanel();
}

function onFilterViewportChange() {
  syncFilterPanelAria();
  if (!filterPanelOpen) return;
  clearDesktopPopoverPosition();
  if (isMobileFilterViewport()) {
    document.body.style.overflow = 'hidden';
  } else {
    document.body.style.overflow = '';
    requestAnimationFrame(() => positionDesktopPopover());
  }
}

function setupFilterPanel() {
  if (filterPanelListenersBound) return;
  filterPanelListenersBound = true;

  const toggle = document.getElementById('filter-toggle-btn');
  const panel = document.getElementById('filter-panel');
  const backdrop = document.getElementById('filter-backdrop');
  const closeBtn = document.getElementById('filter-panel-close');
  const clearBtn = document.getElementById('filter-clear-btn');
  const applyBtn = document.getElementById('filter-apply-btn');
  const typeRow = document.querySelector('.filter-type-row');
  const pillsWrap = document.getElementById('filter-active-pills');

  if (toggle && panel) {
    toggle.addEventListener('click', e => {
      e.stopPropagation();
      if (filterPanelOpen) closeFilterPanel();
      else openFilterPanel();
    });
  }

  if (closeBtn) closeBtn.addEventListener('click', () => closeFilterPanel());
  if (applyBtn) applyBtn.addEventListener('click', () => closeFilterPanel());
  if (clearBtn) clearBtn.addEventListener('click', () => clearAllFilters());

  if (backdrop) {
    backdrop.addEventListener('click', () => closeFilterPanel());
  }

  if (typeRow && !typeRow.dataset.wired) {
    typeRow.dataset.wired = '1';
    typeRow.addEventListener('click', e => {
      const pill = e.target.closest('.filter-type-pill');
      if (!pill || !pill.dataset.type) return;
      const t = pill.dataset.type;
      filterState.type = t;
      typeRow.querySelectorAll('.filter-type-pill').forEach(p => {
        const on = p === pill;
        p.classList.toggle('is-active', on);
        p.setAttribute('aria-pressed', on ? 'true' : 'false');
      });
      saveFilterState();
      applyFilters();
      renderActivePills();
    });
  }

  if (pillsWrap && !pillsWrap.dataset.bound) {
    pillsWrap.dataset.bound = '1';
    pillsWrap.addEventListener('click', e => {
      const btn = e.target.closest('.filter-active-pill');
      if (!btn) return;
      if (btn.dataset.removeType === '1') {
        filterState.type = 'all';
        syncTypePillsUI();
      } else if (btn.dataset.category != null) {
        filterState.categories.delete(btn.dataset.category);
        syncCategoryChipsFromState();
      }
      saveFilterState();
      applyFilters();
      renderActivePills();
    });
  }

  if (panel) {
    panel.addEventListener('keydown', onFilterPanelTabTrap);
  }

  document.addEventListener('click', onFilterDocumentClick);
  document.addEventListener('keydown', onFilterDocumentKeydown);

  if (window.matchMedia) {
    const mq = window.matchMedia('(max-width: 767px)');
    const handler = () => onFilterViewportChange();
    if (mq.addEventListener) mq.addEventListener('change', handler);
    else mq.addListener(handler);
  }

  window.addEventListener('resize', onFilterPanelReposition);
  window.addEventListener('scroll', onFilterPanelReposition, { capture: true, passive: true });
}

async function initGallery() {
  const memes = await loadGalleryList();
  currentGalleryOrder = shuffleArray([...memes]);
  setupLightbox();
  setupSelectedPreviewModal();
  renderGallery(currentGalleryOrder);
  loadFilterState();
  pruneFilterStateToMemes(currentGalleryOrder);
  buildFilterChips(currentGalleryOrder);
  initTypePills(currentGalleryOrder);
  setupFilterPanel();
  applyFilters();
  renderActivePills();

  const randomBtn = document.getElementById('random-meme-btn');
  if (randomBtn) {
    randomBtn.addEventListener('click', () => openRandomMeme(currentGalleryOrder));
  }

  const shuffleBtn = document.getElementById('shuffle-meme-btn');
  if (shuffleBtn) {
    shuffleBtn.addEventListener('click', () => {
      currentGalleryOrder = shuffleArray([...memes]);
      renderGallery(currentGalleryOrder);
      restoreSelectionAfterRender();
      applyFilters();
      updateCountDisplay();
      window.scrollTo({ top: 0, behavior: 'smooth' });
    });
  }

  const params = new URLSearchParams(window.location.search);
  const openMeme = params.get('openMeme');
  if (openMeme && validateImagePath(openMeme)) {
    const openIndex = currentGalleryOrder.indexOf(openMeme);
    if (openIndex >= 0) {
      scrollToMemeCard(openMeme);
      openLightboxAt(openIndex, currentGalleryOrder);
    }
    // Consume one-time deep link so refresh doesn't reopen repeatedly.
    params.delete('openMeme');
    const nextQuery = params.toString();
    const nextUrl = `${window.location.pathname}${nextQuery ? `?${nextQuery}` : ''}${window.location.hash}`;
    window.history.replaceState({}, document.title, nextUrl);
    return;
  }

  if (params.get('randomMeme') === '1') {
    openRandomMeme(currentGalleryOrder, { jumpToCard: true });
    // Consume one-time random trigger so refresh doesn't reopen repeatedly.
    params.delete('randomMeme');
    const nextQuery = params.toString();
    const nextUrl = `${window.location.pathname}${nextQuery ? `?${nextQuery}` : ''}${window.location.hash}`;
    window.history.replaceState({}, document.title, nextUrl);
  }
}

// ====================== ROTATOR (Home Page) ======================
/** Tiny transparent GIF — placeholder so slides without a URL yet don't show a broken icon */
const ROTATOR_PLACEHOLDER =
  'data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7';

let current = 0;
let rotatorStarted = false;

function getMaxRotatorSlides() {
  const conn = typeof navigator !== 'undefined' ? navigator.connection : null;
  if (!conn) return 24;
  if (conn.saveData) return 6;
  const t = conn.effectiveType;
  if (t === 'slow-2g' || t === '2g') return 6;
  if (t === '3g') return 12;
  return 24;
}

function ensureRotatorSlideSrc(img) {
  const path = img.dataset.src;
  if (!path || img.dataset.loaded === '1') return;
  img.src = path;
  img.dataset.loaded = '1';
}

async function startRotator() {
  const container = document.getElementById('meme-rotator');
  if (!container || rotatorStarted) return;
  rotatorStarted = true;

  const sourceList = await loadGalleryList();
  if (!sourceList.length) return;

  const firstImage = sourceList[0];
  const uniqueSources = [...new Set(sourceList)];
  const randomPool = uniqueSources.filter(src => src !== firstImage);
  shuffleArray(randomPool);

  const maxRandomSlides = getMaxRotatorSlides();
  const rotatorList = [firstImage, ...randomPool.slice(0, maxRandomSlides)];

  rotatorList.forEach((src, i) => {
    const img = document.createElement('img');
    img.alt = 'Featured meme preview';
    img.dataset.src = src;
    if (i === 0) {
      img.src = src;
      img.dataset.loaded = '1';
      if ('fetchPriority' in img) img.fetchPriority = 'high';
      img.decoding = 'sync';
    } else {
      img.src = ROTATOR_PLACEHOLDER;
      img.loading = 'lazy';
      img.decoding = 'async';
    }
    if (i === 0) img.classList.add('active');
    container.appendChild(img);
  });

  container.addEventListener('click', () => {
    const activeImg = container.querySelector('img.active');
    if (!activeImg) return;
    const src = activeImg.dataset.src || activeImg.getAttribute('src');
    if (!src || src === ROTATOR_PLACEHOLDER) return;
    const target = `memes.html?openMeme=${encodeURIComponent(src)}`;
    window.location.href = target;
  });

  const len = rotatorList.length;
  setInterval(() => {
    const imgs = container.querySelectorAll('img');
    if (imgs.length === 0) return;
    const next = (current + 1) % len;
    ensureRotatorSlideSrc(imgs[next]);
    imgs[current].classList.remove('active');
    current = next;
    imgs[current].classList.add('active');
  }, 3000);
}

let selected = new Set();
let lightboxMemes = [];
let lightboxIndex = 0;

function restoreSelectionAfterRender() {
  document.querySelectorAll('.meme-card').forEach(card => {
    const src = card.dataset.src;
    if (!src) return;
    card.classList.toggle('selected', selected.has(src));
  });
  updateSelectedUI();
}

function setupLightbox() {
  if (document.getElementById('meme-lightbox')) return;

  const overlay = document.createElement('div');
  overlay.id = 'meme-lightbox';
  overlay.className = 'meme-lightbox';
  overlay.setAttribute('aria-hidden', 'true');
  overlay.innerHTML = `
    <button type="button" class="meme-lightbox-close" id="meme-lightbox-close" aria-label="Close lightbox">CLOSE</button>
    <button type="button" class="meme-lightbox-nav prev" id="meme-lightbox-prev" aria-label="Previous meme">PREV</button>
    <button type="button" class="meme-lightbox-nav random" id="meme-lightbox-random" aria-label="Random meme">RANDOM</button>
    <div class="meme-lightbox-frame">
      <img id="meme-lightbox-image" alt="Selected meme preview">
    </div>
    <button type="button" class="meme-lightbox-nav next" id="meme-lightbox-next" aria-label="Next meme">NEXT</button>
    <div class="meme-lightbox-actions">
      <button type="button" class="button meme-lightbox-action" id="meme-lightbox-download">DOWNLOAD THIS MEME</button>
      <button type="button" class="button meme-lightbox-action" id="meme-lightbox-toggle-select">ADD TO DOWNLOADS</button>
      <button type="button" class="button meme-lightbox-action" id="meme-lightbox-selected-preview">VIEW SELECTED</button>
      <button type="button" class="button meme-lightbox-action" id="meme-lightbox-download-zip">DOWNLOAD ZIP</button>
    </div>
  `;
  document.body.appendChild(overlay);

  overlay.addEventListener('click', (event) => {
    if (event.target === overlay) closeLightbox();
  });

  document.getElementById('meme-lightbox-close').addEventListener('click', closeLightbox);
  document.getElementById('meme-lightbox-prev').addEventListener('click', () => shiftLightbox(-1));
  document.getElementById('meme-lightbox-next').addEventListener('click', () => shiftLightbox(1));
  document.getElementById('meme-lightbox-random').addEventListener('click', jumpToRandomLightboxMeme);
  document.getElementById('meme-lightbox-download').addEventListener('click', downloadCurrentLightboxMeme);
  document.getElementById('meme-lightbox-toggle-select').addEventListener('click', toggleCurrentLightboxSelection);
  document.getElementById('meme-lightbox-selected-preview').addEventListener('click', openSelectedPreviewModal);
  document.getElementById('meme-lightbox-download-zip').addEventListener('click', () => downloadSelectedAsZip());
  const frame = overlay.querySelector('.meme-lightbox-frame');
  if (frame) {
    frame.addEventListener('click', toggleCurrentLightboxSelection);
  }

  document.addEventListener('keydown', (event) => {
    if (!overlay.classList.contains('open')) return;
    if (event.key === 'Escape') closeLightbox();
    if (event.key === 'ArrowLeft') shiftLightbox(-1);
    if (event.key === 'ArrowRight') shiftLightbox(1);
  });
}

function openLightboxAt(index, memes) {
  if (!Array.isArray(memes) || memes.length === 0) return;
  lightboxMemes = memes;
  lightboxIndex = index;
  const overlay = document.getElementById('meme-lightbox');
  if (!overlay) return;
  overlay.classList.add('open');
  overlay.setAttribute('aria-hidden', 'false');
  document.body.style.overflow = 'hidden';
  syncLightbox();
}

function closeLightbox() {
  const overlay = document.getElementById('meme-lightbox');
  if (!overlay) return;
  overlay.classList.remove('open');
  overlay.setAttribute('aria-hidden', 'true');
  document.body.style.overflow = '';
}

function shiftLightbox(direction) {
  if (!lightboxMemes.length) return;
  lightboxIndex = (lightboxIndex + direction + lightboxMemes.length) % lightboxMemes.length;
  syncLightbox();
}

function jumpToRandomLightboxMeme() {
  if (!lightboxMemes.length) return;
  if (lightboxMemes.length === 1) {
    syncLightbox();
    return;
  }

  let randomIndex = lightboxIndex;
  while (randomIndex === lightboxIndex) {
    randomIndex = Math.floor(Math.random() * lightboxMemes.length);
  }

  lightboxIndex = randomIndex;
  syncLightbox();
}

function syncLightbox() {
  const img = document.getElementById('meme-lightbox-image');
  const frame = document.querySelector('.meme-lightbox-frame');
  const toggleBtn = document.getElementById('meme-lightbox-toggle-select');
  const zipBtn = document.getElementById('meme-lightbox-download-zip');
  if (!img || !toggleBtn || !lightboxMemes.length) return;
  const src = lightboxMemes[lightboxIndex];
  const isSelected = selected.has(src);
  img.decoding = 'async';
  if ('fetchPriority' in img) img.fetchPriority = 'high';
  img.src = src;
  img.alt = `FuqMeA Meme ${lightboxIndex + 1}`;
  toggleBtn.textContent = isSelected ? 'REMOVE FROM DOWNLOADS' : 'ADD TO DOWNLOADS';
  if (frame) frame.classList.toggle('selected', isSelected);
  if (zipBtn) zipBtn.disabled = selected.size === 0;
}

function toggleCurrentLightboxSelection() {
  if (!lightboxMemes.length) return;
  const src = lightboxMemes[lightboxIndex];
  const safeSrc = typeof CSS !== 'undefined' && CSS.escape ? CSS.escape(src) : src.replace(/"/g, '\\"');
  const card = document.querySelector(`.meme-card[data-src="${safeSrc}"]`);
  if (!card) return;
  const img = card.querySelector('img');
  if (!img) return;
  toggleSelect(img);
  syncLightbox();
}

async function downloadSingleMeme(src) {
  try {
    if (!validateImagePath(src)) return;
    const extension = getExtensionFromPath(src);
    const filename = getRandomMemeFilename(extension);
    const response = await fetch(src);
    if (!response.ok) throw new Error('Fetch failed');
    const blob = await response.blob();
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(link.href);
  } catch (err) {
    console.error('Single meme download failed');
  }
}

async function downloadCurrentLightboxMeme() {
  if (!lightboxMemes.length) return;
  await downloadSingleMeme(lightboxMemes[lightboxIndex]);
}

function scrollToMemeCard(src) {
  const safeSrc = typeof CSS !== 'undefined' && CSS.escape ? CSS.escape(src) : src.replace(/"/g, '\\"');
  const targetCard = document.querySelector(`.meme-card[data-src="${safeSrc}"]`);
  if (!targetCard) return;
  // Jump directly to the card position (no animated scroll).
  targetCard.scrollIntoView({ behavior: 'auto', block: 'center' });
}

function openRandomMeme(memes, options = {}) {
  if (!Array.isArray(memes) || memes.length === 0) return;
  const randomIndex = Math.floor(Math.random() * memes.length);
  if (options.jumpToCard) {
    const randomSrc = memes[randomIndex];
    if (randomSrc) scrollToMemeCard(randomSrc);
  }
  openLightboxAt(randomIndex, memes);
}

window.toggleSelect = function(img) {
  const card = img.parentElement;
  const src = card.dataset.src;
  
  if (selected.has(src)) {
    selected.delete(src);
    card.classList.remove('selected');
  } else {
    selected.add(src);
    card.classList.add('selected');
  }
  
  updateSelectedUI();
  const overlay = document.getElementById('meme-lightbox');
  if (overlay && overlay.classList.contains('open')) {
    syncLightbox();
  }
};

window.deselectAll = function() {
  selected.clear();
  document.querySelectorAll('.meme-card.selected').forEach(card => {
    card.classList.remove('selected');
  });
  updateSelectedUI();
};

window.selectAll = function() {
  document.querySelectorAll('.meme-card').forEach(card => {
    const src = card.dataset.src;
    if (!src) return;
    selected.add(src);
    card.classList.add('selected');
  });
  updateSelectedUI();
};

function setupSelectedPreviewModal() {
  if (document.getElementById('selected-preview-modal')) return;

  const modal = document.createElement('div');
  modal.id = 'selected-preview-modal';
  modal.className = 'selected-preview-modal';
  modal.setAttribute('aria-hidden', 'true');
  modal.innerHTML = `
    <div class="selected-preview-panel" role="dialog" aria-modal="true" aria-labelledby="selected-preview-title">
      <div class="selected-preview-header">
        <h2 id="selected-preview-title">Selected Memes</h2>
        <button type="button" class="selected-preview-close" id="selected-preview-close" aria-label="Close selected preview">CLOSE</button>
      </div>
      <div class="selected-preview-table-wrap">
        <table class="selected-preview-table">
          <thead>
            <tr>
              <th>Preview</th>
              <th>File</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody id="selected-preview-body"></tbody>
        </table>
      </div>
    </div>
  `;
  document.body.appendChild(modal);

  const topPreviewBtn = document.getElementById('selected-preview-btn');
  if (topPreviewBtn) {
    topPreviewBtn.addEventListener('click', openSelectedPreviewModal);
  }

  document.getElementById('selected-preview-close').addEventListener('click', closeSelectedPreviewModal);
  modal.addEventListener('click', (event) => {
    if (event.target === modal) closeSelectedPreviewModal();
  });
}

function openSelectedPreviewModal() {
  renderSelectedPreviewModal();
  const modal = document.getElementById('selected-preview-modal');
  if (!modal) return;
  modal.classList.add('open');
  modal.setAttribute('aria-hidden', 'false');
}

function closeSelectedPreviewModal() {
  const modal = document.getElementById('selected-preview-modal');
  if (!modal) return;
  modal.classList.remove('open');
  modal.setAttribute('aria-hidden', 'true');
}

function renderSelectedPreviewModal() {
  const body = document.getElementById('selected-preview-body');
  if (!body) return;
  body.innerHTML = '';

  if (selected.size === 0) {
    const row = document.createElement('tr');
    const cell = document.createElement('td');
    cell.colSpan = 3;
    cell.textContent = 'No memes selected yet.';
    row.appendChild(cell);
    body.appendChild(row);
    return;
  }

  Array.from(selected).forEach((src) => {
    const filename = src.split('/').pop() || 'meme-file';
    const row = document.createElement('tr');

    const previewCell = document.createElement('td');
    const img = document.createElement('img');
    img.src = src;
    img.alt = 'Selected meme thumbnail';
    img.className = 'selected-preview-thumb';
    previewCell.appendChild(img);

    const fileCell = document.createElement('td');
    fileCell.textContent = filename;

    const actionsCell = document.createElement('td');
    const viewBtn = document.createElement('button');
    viewBtn.type = 'button';
    viewBtn.className = 'selected-preview-action';
    viewBtn.textContent = 'View';
    viewBtn.addEventListener('click', () => {
      if (!lightboxMemes.length) return;
      const idx = lightboxMemes.indexOf(src);
      if (idx >= 0) {
        closeSelectedPreviewModal();
        openLightboxAt(idx, lightboxMemes);
      }
    });

    const removeBtn = document.createElement('button');
    removeBtn.type = 'button';
    removeBtn.className = 'selected-preview-action remove';
    removeBtn.textContent = 'Remove';
    removeBtn.addEventListener('click', () => {
      selected.delete(src);
      const safeSrc = typeof CSS !== 'undefined' && CSS.escape ? CSS.escape(src) : src.replace(/"/g, '\\"');
      const card = document.querySelector(`.meme-card[data-src="${safeSrc}"]`);
      if (card) card.classList.remove('selected');
      updateSelectedUI();
      if (selected.size === 0) closeSelectedPreviewModal();
    });

    actionsCell.appendChild(viewBtn);
    actionsCell.appendChild(removeBtn);

    row.appendChild(previewCell);
    row.appendChild(fileCell);
    row.appendChild(actionsCell);
    body.appendChild(row);
  });
}

function updateSelectedUI() {
  const previewBtn = document.getElementById('selected-preview-btn');
  const zipBtn = document.getElementById('download-zip-btn');
  const deselectBtn = document.getElementById('deselect-all-btn');
  const lightboxPreviewBtn = document.getElementById('meme-lightbox-selected-preview');
  const lightboxZipBtn = document.getElementById('meme-lightbox-download-zip');
  const selectedCount = selected.size;
  const zipLabel = `DOWNLOAD ZIP (${selectedCount})`;
  const previewLabel = `VIEW SELECTED (${selectedCount})`;
  
  if (previewBtn) {
    previewBtn.style.display = selectedCount > 0 ? 'inline-block' : 'none';
    previewBtn.textContent = previewLabel;
  }
  if (zipBtn) {
    zipBtn.style.display = selectedCount > 0 ? 'inline-block' : 'none';
    zipBtn.textContent = zipLabel;
  }
  if (deselectBtn) deselectBtn.style.display = selectedCount > 0 ? 'inline-block' : 'none';
  if (lightboxPreviewBtn) {
    lightboxPreviewBtn.disabled = selectedCount === 0;
    lightboxPreviewBtn.textContent = previewLabel;
  }
  if (lightboxZipBtn) {
    lightboxZipBtn.disabled = selectedCount === 0;
    lightboxZipBtn.textContent = zipLabel;
  }
  renderSelectedPreviewModal();
}

// ZIP Download
document.addEventListener('DOMContentLoaded', () => {
  const zipBtn = document.getElementById('download-zip-btn');
  if (zipBtn) {
    zipBtn.addEventListener('click', () => downloadSelectedAsZip(zipBtn));
  }
  
  const deselectBtn = document.getElementById('deselect-all-btn');
  if (deselectBtn) {
    deselectBtn.addEventListener('click', deselectAll);
  }

  const scrollBtn = document.getElementById('scroll-top-btn');
  if (scrollBtn) {
    window.addEventListener('scroll', throttle(() => {
      scrollBtn.classList.toggle('visible', window.scrollY > 600);
    }, 100));
    scrollBtn.addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));
  }

  const selectAllBtn = document.getElementById('select-all-btn');
  if (selectAllBtn) {
    selectAllBtn.addEventListener('click', selectAll);
  }

  // Delegated fallback so preview buttons still work
  document.addEventListener('click', (event) => {
    const target = event.target;
    if (!(target instanceof Element)) return;
    const previewTrigger = target.closest('#selected-preview-btn, #meme-lightbox-selected-preview');
    if (previewTrigger) {
      openSelectedPreviewModal();
    }
  });
});

async function downloadSelectedAsZip(triggerButton) {
  if (selected.size === 0) return;

  try {
    if (!window.JSZip) {
      alert('Download library not loaded. Please refresh the page.');
      return;
    }

    if (triggerButton) {
      triggerButton.disabled = true;
      triggerButton.textContent = 'DOWNLOADING...';
    }

    const zip = new window.JSZip();
    const usedNames = new Set();
    const promises = Array.from(selected).map(async (src) => {
      try {
        if (!validateImagePath(src)) return;
        const extension = getExtensionFromPath(src);
        const filename = getRandomMemeFilename(extension, usedNames);
        const response = await fetch(src);
        if (!response.ok) throw new Error('Fetch failed');
        const blob = await response.blob();
        zip.file(filename, blob);
      } catch (err) {
        console.error('Image fetch error (non-critical)');
      }
    });

    await Promise.all(promises);
    const content = await zip.generateAsync({ type: 'blob' });

    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `meme_pack_${Math.floor(1000 + Math.random() * 9000)}.zip`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(link.href);
  } catch (err) {
    console.error('Download error occurred');
    alert('Download failed. Please try again.');
  } finally {
    if (triggerButton) {
      triggerButton.disabled = false;
    }
    updateSelectedUI();
  }
}

// ====================== LIVE STATUS (TIKTOK + TWITCH) ======================

// Master switch: when false, live checks stay disabled across all pages.
const LIVE_STATUS_ENABLED = false;
const LIVE_STATUS_INTERVAL_MS = 45000;

// Rate limiting and error tracking
const liveStatusCache = new Map();
const liveStatusErrors = new Map();
const MAX_ERRORS = 3;
const ERROR_RESET_TIME = 300000; // 5 minutes
let liveStatusIntervalId = null;
let liveStatusMockMap = new Map();

function parseMockLiveStatuses() {
  const params = new URLSearchParams(window.location.search);
  const mockLiveParam = params.get('mockLive');
  const result = new Map();
  if (!mockLiveParam) return result;

  // Format: ?mockLive=ssgvivid:tiktok:420,steggyful1:twitch:77
  mockLiveParam.split(',').map(x => x.trim()).filter(Boolean).forEach(entry => {
    const [usernameRaw, platformRaw, viewersRaw] = entry.split(':');
    const username = (usernameRaw || '').trim().toLowerCase();
    const platform = (platformRaw || '').trim().toLowerCase();
    const viewers = Number.parseInt((viewersRaw || '').trim(), 10);
    if (!username || (platform !== 'tiktok' && platform !== 'twitch' && platform !== 'both')) return;
    result.set(username, {
      platform,
      viewers: Number.isFinite(viewers) ? viewers : null
    });
  });

  return result;
}

async function fetchWithTimeout(resource, options = {}, timeoutMs = 8000) {
  if (!('AbortController' in window)) {
    return fetch(resource, options);
  }
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(resource, { ...options, signal: controller.signal });
  } finally {
    clearTimeout(timer);
  }
}

// ---- TWITCH ----
async function checkTwitchLive(username) {
  try {
    const safeUsername = encodeURIComponent(username);
    const res = await fetchWithTimeout(`https://decapi.me/twitch/uptime/${safeUsername}`);
    if (!res.ok) return { live: false };
    const text = await res.text();
    return { live: !text.includes("offline"), viewers: null, platform: 'twitch' };
  } catch (e) {
    console.warn('Twitch check failed for', username);
    return { live: false };
  }
}

// ---- TIKTOK ----
async function checkTikTokLive(username) {
  try {
    const safeUsername = encodeURIComponent(username);
    const res = await fetchWithTimeout(`https://www.tiktok.com/@${safeUsername}/live`);
    if (!res.ok) return { live: false };
    const text = await res.text();
    const isLive = text.includes('"isLiveBroadcast":true') || text.includes('"liveRoomId"');
    if (!isLive) return { live: false };
    
    let viewers = null;
    const match = text.match(/"user_count":(\d+)/);
    if (match) viewers = parseInt(match[1]);
    return { live: true, viewers, platform: 'tiktok' };
  } catch (e) {
    console.warn('TikTok check failed for', username);
    return { live: false };
  }
}

function formatViewerCount(viewers) {
  if (!Number.isFinite(viewers) || viewers < 0) return '';
  if (viewers >= 1000000) return `${(viewers / 1000000).toFixed(1).replace('.0', '')}M`;
  if (viewers >= 1000) return `${(viewers / 1000).toFixed(1).replace('.0', '')}K`;
  return `${viewers}`;
}

function setStreamerStatus(dot, text, streamerBtn, streamerSection, status) {
  if (!dot || !text) return;
  text.setAttribute('aria-live', 'polite');
  text.setAttribute('role', 'status');

  const targets = [streamerBtn, streamerSection].filter(Boolean);
  targets.forEach(el => {
    el.classList.remove('live', 'offline', 'checking');
    el.classList.add(status.state);
  });

  if (status.state === 'live') {
    const viewersText = formatViewerCount(status.viewers);
    text.textContent = viewersText
      ? `LIVE • ${viewersText} viewers`
      : 'LIVE';
    return;
  }

  if (status.state === 'checking') {
    text.textContent = 'CHECKING...';
    return;
  }

  text.textContent = 'OFFLINE';
}

function setPlatformLiveButtons(streamerSection, tiktokLive, twitchLive) {
  if (!streamerSection) return;
  const links = streamerSection.querySelectorAll('a.button');
  links.forEach(link => {
    const href = link.getAttribute('href') || '';
    const isTikTokLink = href.includes('tiktok.com');
    const isTwitchLink = href.includes('twitch.tv');
    const shouldPulse = (isTikTokLink && tiktokLive) || (isTwitchLink && twitchLive);
    link.classList.toggle('platform-live', shouldPulse);
    link.setAttribute('aria-live', shouldPulse ? 'polite' : 'off');
  });
}

function setLiveStatusVisibility(enabled) {
  const streamers = document.querySelectorAll('.streamers');
  streamers.forEach(el => {
    el.style.display = enabled ? 'flex' : 'none';
  });
}

function setStreamerCardVisibility(username, isVisible) {
  const headerCards = document.querySelectorAll(`.streamer-btn[data-streamer="${username}"]`);
  headerCards.forEach(card => {
    card.style.display = isVisible ? 'flex' : 'none';
  });
}

function refreshHeaderLiveStripVisibility() {
  const wrappers = document.querySelectorAll('.streamers');
  wrappers.forEach(wrapper => {
    const visibleCards = wrapper.querySelectorAll('.streamer-btn.live');
    wrapper.style.display = visibleCards.length > 0 ? 'flex' : 'none';
  });
}

// ---- COMBINED with Rate Limiting ----
async function updateStreamerLive(username, dotId, textId) {
  const dot = document.getElementById(dotId);
  const text = document.getElementById(textId);
  if (!dot || !text) return;

  const streamerBtn = dot.closest('.streamer-btn');
  const streamerSection = document.querySelector(`.streamer-section[data-streamer="${username}"]`);
  const normalizedUsername = username.toLowerCase();

  if (!LIVE_STATUS_ENABLED) {
    setStreamerStatus(dot, text, streamerBtn, streamerSection, { state: 'offline' });
    setStreamerCardVisibility(username, false);
    refreshHeaderLiveStripVisibility();
    return;
  }

  const mockStatus = liveStatusMockMap.get(normalizedUsername);
  if (mockStatus) {
    const tiktokLive = mockStatus.platform === 'tiktok' || mockStatus.platform === 'both';
    const twitchLive = mockStatus.platform === 'twitch' || mockStatus.platform === 'both';
    const platform = tiktokLive ? 'tiktok' : 'twitch';

    setStreamerStatus(dot, text, streamerBtn, streamerSection, {
      state: 'live',
      viewers: mockStatus.viewers,
      platform
    });
    setPlatformLiveButtons(streamerSection, tiktokLive, twitchLive);
    setStreamerCardVisibility(username, true);
    refreshHeaderLiveStripVisibility();
    return;
  }

  // Check error count and apply backoff
  const errorCount = liveStatusErrors.get(username) || 0;
  if (errorCount >= MAX_ERRORS) {
    console.warn(`Too many errors for ${username}, skipping check`);
    return;
  }

  try {
    const [tiktok, twitch] = await Promise.all([
      checkTikTokLive(username),
      checkTwitchLive(username)
    ]);
    const isLive = tiktok.live || twitch.live;

    if (isLive) {
      const viewers = Number.isFinite(tiktok.viewers) ? tiktok.viewers : twitch.viewers;
      const platform = tiktok.live ? tiktok.platform : twitch.platform;
      setStreamerStatus(dot, text, streamerBtn, streamerSection, {
        state: 'live',
        viewers,
        platform
      });
      setPlatformLiveButtons(streamerSection, tiktok.live, twitch.live);
      setStreamerCardVisibility(username, true);
    } else {
      setStreamerStatus(dot, text, streamerBtn, streamerSection, { state: 'offline' });
      setPlatformLiveButtons(streamerSection, false, false);
      setStreamerCardVisibility(username, false);
    }
    refreshHeaderLiveStripVisibility();
    
    // Reset error count on success
    liveStatusErrors.delete(username);
    liveStatusCache.set(username, { isLive, checkedAt: Date.now() });
  } catch (err) {
    const newErrorCount = (liveStatusErrors.get(username) || 0) + 1;
    liveStatusErrors.set(username, newErrorCount);
    console.error(`Live status error for ${username} (attempt ${newErrorCount})`);
    // Keep last known UI state to avoid visual flicker during transient request failures.
    window.setTimeout(() => liveStatusErrors.delete(username), ERROR_RESET_TIME);
  }
}

// ---- INIT ----
function initLiveStatus() {
  liveStatusMockMap = parseMockLiveStatuses();
  // Avoid header-strip flash on load: keep hidden until we have confirmed live data.
  setLiveStatusVisibility(false);
  setStreamerCardVisibility('steggyful1', false);
  setStreamerCardVisibility('ssgvivid', false);

  if (!LIVE_STATUS_ENABLED) {
    updateStreamerLive("steggyful1", "live-steggyful1", "live-text-steggyful1");
    updateStreamerLive("ssgvivid", "live-ssgvivid", "live-text-ssgvivid");
    return;
  }

  updateStreamerLive("steggyful1", "live-steggyful1", "live-text-steggyful1");
  updateStreamerLive("ssgvivid", "live-ssgvivid", "live-text-ssgvivid");

  liveStatusIntervalId = window.setInterval(() => {
    if (document.hidden) return;
    updateStreamerLive("steggyful1", "live-steggyful1", "live-text-steggyful1");
    updateStreamerLive("ssgvivid", "live-ssgvivid", "live-text-ssgvivid");
  }, LIVE_STATUS_INTERVAL_MS);

  // Debounce visibility change to avoid flashing when switching tabs
  // Only re-check if cache is stale (older than 10 seconds)
  let visibilityTimeout;
  document.addEventListener('visibilitychange', () => {
    if (!document.hidden) {
      clearTimeout(visibilityTimeout);
      // Wait 500ms before checking, and only if cache is stale
      visibilityTimeout = setTimeout(() => {
        const now = Date.now();
        const cache1 = liveStatusCache.get('steggyful1');
        const cache2 = liveStatusCache.get('ssgvivid');
        const cacheAge1 = cache1 ? now - cache1.checkedAt : Infinity;
        const cacheAge2 = cache2 ? now - cache2.checkedAt : Infinity;
        
        // Only update if cache is older than 10 seconds
        if (cacheAge1 > 10000 || cacheAge2 > 10000) {
          updateStreamerLive("steggyful1", "live-steggyful1", "live-text-steggyful1");
          updateStreamerLive("ssgvivid", "live-ssgvivid", "live-text-ssgvivid");
        }
      }, 500);
    }
  });
}